body {
  font-family: "Your Display Font", sans-serif;
  font-optical-sizing: auto; /* Activates optical sizing if font supports it */
  text-rendering: optimizeLegibility; /* Also helps with overall rendering */
}

h1 {
  font-size: 4rem;
  font-optical-sizing: auto; /* Ensures large headings are precisely rendered */
}

p {
  font-size: 1.125rem;
  font-optical-sizing: auto; /* Improves readability of body text */
}
